INSERT INTO public.products (name, description, price, category, stock_quantity, rating, reviews_count, is_active) VALUES
('أشواجاندا', 'مكمل أشواجاندا الممتاز لدعم صحتك العامة وتعزيز نشاطك اليومي. مستخرج من جذور الأشواجاندا الهندية الأصيلة.', 123, 'مكملات غذائية', 42, 4.8, 124, true),
('بيوتين', 'مكمل بيوتين الممتاز لدعم صحة الشعر والأظافر والبشرة. تركيز عالي 10000 mcg.', 224, 'مكملات غذائية', 58, 4.7, 89, true),
('كولاجين بحري', 'مكمل كولاجين الممتاز لدعم صحة البشرة والمفاصل والشعر. مستخرج من زعانف السمك.', 204, 'مكملات غذائية', 33, 4.6, 67, true),
('جلوتاثيون', 'مكمل إل-جلوتاثيون الممتاز - مضاد أكسدة قوي لتفتيح البشرة وحماية الكبد.', 141, 'مكملات غذائية', 12, 4.5, 45, true),
('مغنيسيوم', 'مكمل مغنيسيوم الممتاز لدعم صحة العضلات والنوم والجهاز العصبي.', 191, 'مكملات غذائية', 35, 4.6, 78, true),
('مستكة رومية', 'مكمل مستكة الممتاز لعلاج قرحة المعدة والقولون وتطهير الفم. من جزيرة خيوس اليونانية.', 145, 'مكملات غذائية', 17, 4.8, 92, true),
('فيتامينات متعددة', 'مكمل فيتامينات متعددة الممتاز - 23 فيتاميناً ومعدناً أساسياً في كبسولة واحدة يومياً.', 92, 'مكملات غذائية', 19, 4.4, 56, true),
('أوميغا 3 سمك', 'مكمل أوميغا 3 من زيت السمك الممتاز لصحة القلب والمخ والمفاصل.', 148, 'مكملات غذائية', 21, 4.7, 103, true),
('أوميغا 3 نباتي', 'مكمل أوميغا 3 النباتي الممتاز من بذور الكتان - مناسب للنباتيين.', 244, 'مكملات غذائية', 34, 4.5, 61, true),
('بروبيوتيك', 'مكمل بروبيوتيك الممتاز - 50 مليار CFU من 12 سلالة بكتيرية لصحة الجهاز الهضمي.', 144, 'مكملات غذائية', 37, 4.6, 88, true),
('شيلاجيت', 'مكمل شيلاجيت الممتاز من جبال الهيمالايا لزيادة الطاقة والتستوستيرون.', 130, 'مكملات غذائية', 47, 4.9, 134, true),
('فيتامين D3 + K2', 'مكمل فيتامين D3 مع K2 الممتاز لتقوية العظام والمناعة. 5000 IU يومياً.', 171, 'مكملات غذائية', 26, 4.8, 97, true),
('زنك', 'مكمل زنك الممتاز لتعزيز المناعة وصحة الجلد والخصوبة. جلوكونات الزنك عالي الامتصاص.', 68, 'مكملات غذائية', 15, 4.5, 43, true);
INSERT INTO public.products (name, description, price, category, stock_quantity, rating, reviews_count, is_active) VALUES
('ألوفيرا (صبار)', 'جل الصبار الطبيعي النقي من نباتات عمرها 3 سنوات. يهدئ الجلد ويدعم الهضم.', 180, 'أعشاب طبية', 49, 4.7, 112, true),
('بابونج عضوي', 'أعشاب البابونج طبيعية وعضوية من أجود المصادر. مهدئ طبيعي للأعصاب والمعدة.', 249, 'أعشاب طبية', 27, 4.8, 98, true),
('قرفة سيلان', 'أعشاب القرفة الأصيلة من سيلان (سريلانكا). تنظم سكر الدم وتحسن الهضم.', 47, 'أعشاب طبية', 56, 4.5, 67, true),
('زنجبيل طازج', 'أعشاب الزنجبيل طبيعية وعضوية - مضاد التهابات قوي، يخفف الغثيان والآلام.', 235, 'أعشاب طبية', 35, 4.7, 89, true),
('كركديه', 'أعشاب الكركديه طبيعية وعضوية. تخفض ضغط الدم وتحسن الكوليسترول وغنية بفيتامين C.', 86, 'أعشاب طبية', 45, 4.6, 76, true),
('خزامى (لافندر)', 'أعشاب لافندر طبيعية وعضوية من جبال الأطلس. تخفف القلق والتوتر وتحسن النوم.', 107, 'أعشاب طبية', 52, 4.8, 104, true),
('لويزة (فيرفين)', 'أعشاب اللويزة المغربية الأصيلة. العشب المفضل في كل بيت مغربي لتهدئة المعدة والصداع.', 192, 'أعشاب طبية', 51, 4.9, 156, true),
('نعناع مغربي', 'أعشاب النعناع المغربي الأصيل. منشط طبيعي، يحسن الهضم ويخفف الصداع.', 110, 'أعشاب طبية', 30, 4.7, 87, true),
('إكليل الجبل (روزماري)', 'أعشاب إكليل الجبل طبيعية. يحفز الذاكرة والتركيز ويقوي الشعر.', 96, 'أعشاب طبية', 17, 4.5, 54, true),
('مريمية', 'أعشاب المريمية طبيعية وعضوية. تنظم الدورة الشهرية وتخفف أعراض انقطاع الطمث.', 205, 'أعشاب طبية', 27, 4.6, 72, true),
('زعتر بري', 'أعشاب الزعتر البري من جبال الريف. غني بالزيوت الطيارة المضادة للميكروبات.', 143, 'أعشاب طبية', 52, 4.7, 93, true),
('كركم ذهبي', 'أعشاب الكركم طبيعية وعضوية. مضاد التهابات قوي يدعم المفاصل والكبد والهضم.', 125, 'أعشاب طبية', 33, 4.8, 118, true),
('أوراق الزيتون', 'أوراق الزيتون المجففة الغنية بالأوليوروبين. تخفض ضغط الدم وتعزز المناعة.', 180, 'أعشاب طبية', 49, 4.6, 84, true),
('إشنسا (Echinacea)', 'مستخلص نبات الإشنسا المعزز للمناعة. يقلل مدة الإصابة بالبرد والأنفلونزا.', 249, 'أعشاب طبية', 27, 4.7, 96, true);
INSERT INTO public.products (name, description, price, category, stock_quantity, rating, reviews_count, is_active) VALUES
('زيت اللوز الحلو', 'زيت اللوز العضوي النقي المعصور بالبرد. مرطب ممتاز للجلد والشعر غني بفيتامين E.', 69, 'زيوت طبية', 39, 4.5, 63, true),
('زيت أرغان المغربي', 'زيت أرغان العضوي النقي من فاس - الذهب السائل المغربي. يغذي الشعر والبشرة.', 215, 'زيوت طبية', 14, 4.9, 187, true),
