('زيت الخروع', 'زيت الخروع العضوي النقي - الجامايكي الأسود. يكثف الشعر ويسرع نموه ويقوي الرموش.', 197, 'زيوت طبية', 22, 4.6, 98, true),
('زيت الزنجبيل', 'زيت الزنجبيل العضوي النقي. يدفئ المفاصل ويخفف آلام الظهر والعضلات عند التدليك.', 181, 'زيوت طبية', 15, 4.5, 57, true),
('زيت الثوم', 'زيت الثوم العضوي النقي. مضاد حيوي طبيعي، يخفض ضغط الدم ويعزز المناعة.', 71, 'زيوت طبية', 52, 4.4, 45, true),
('زيت الخزامى (لافندر)', 'زيت خزامى العضوي النقي 100% المقطر ببخار الماء. يهدئ التوتر ويعالج جروح الجلد.', 64, 'زيوت طبية', 48, 4.8, 112, true),
('زيت المسك', 'زيت المسك العضوي النقي - بعطره الشرقي الأصيل. يستخدم في العطور والعلاج الروحي.', 170, 'زيوت طبية', 59, 4.7, 87, true),
('زيت الزيتون البكر', 'زيت الزيتون العضوي النقي البكر الممتاز المعصور بالبرد. حموضة أقل من 0.3%.', 212, 'زيوت طبية', 33, 4.7, 104, true),
('زيت الورد', 'زيت الورد العضوي النقي من بتلات الورد البلغارية. أكثر الزيوت فعالية لتجديد البشرة.', 202, 'زيوت طبية', 21, 4.9, 134, true),
('زيت السدر', 'زيت سدر العضوي النقي. يقوي بصيلات الشعر ويعالج قشرة الرأس ويكثف الشعر.', 158, 'زيوت طبية', 36, 4.6, 76, true),
('زيت الحبة السوداء الممتاز', 'زيت حبة السوداء الممتاز المركز بتركيز 3X أقوى. للمناعة القصوى ومكافحة الالتهابات.', 132, 'زيوت طبية', 17, 4.9, 178, true);
INSERT INTO public.products (name, description, price, category, stock_quantity, rating, reviews_count, is_active) VALUES
('عسل الطلح (أكاسيا)', 'عسل طلح طبيعي نقي 100%. شفاف منخفض الغلايسيميك، مناسب لمرضى السكر ويبقى سائلاً طويلاً.', 120, 'عسل طبيعي', 20, 4.6, 87, true),
('عسل الحبة السوداء', 'عسل الحبة السوداء طبيعي نقي 100%. يجمع بين خصائص العسل والحبة السوداء - تراث نبوي.', 231, 'عسل طبيعي', 59, 4.8, 143, true),
('عسل الخروب', 'عسل الخروب طبيعي نقي 100%. داكن اللون قوي الطعم، يقوي الجهاز الهضمي ويعالج الإمساك.', 94, 'عسل طبيعي', 30, 4.5, 67, true),
('عسل الداغموس', 'عسل الداغموس الجبلي النادر من جبال الأطلس. يستخدم تقليدياً لتقوية الظهر وعلاج الروماتيزم.', 91, 'عسل طبيعي', 28, 4.7, 98, true),
('عسل الكافور (إكاليبتوس)', 'عسل كافور طبيعي نقي 100%. يعالج التهابات الجهاز التنفسي والحمى والأنفلونزا.', 184, 'عسل طبيعي', 34, 4.6, 76, true),
('عسل الأزهار', 'عسل الأزهار البرية الطبيعي نقي 100%. من تنوع أزهار المرج المغربي في فصل الربيع.', 136, 'عسل طبيعي', 52, 4.5, 89, true),
('عسل الغابة', 'عسل الغابة البكر من النحل البري في غابات الأطلس الكبير. نكهة غنية بمزيج الأزهار.', 128, 'عسل طبيعي', 26, 4.8, 112, true),
('عسل المانوكا', 'عسل مانوكا طبيعي نقي 100% من نيوزيلندا. يعالج جروح الجلد ويقاوم البكتيريا المقاومة.', 184, 'عسل طبيعي', 59, 4.9, 187, true),
('عسل زهر البرتقال', 'عسل زهر البرتقال الطبيعي من حدائق الصويرة. أبيض اللون خفيف الملمس مناسب للأطفال.', 173, 'عسل طبيعي', 54, 4.7, 103, true),
('عسل السدر', 'عسل سدر طبيعي نقي 100% من جبال الأطلس. يقوي المناعة ويعالج الأنيميا ويرفع الطاقة.', 119, 'عسل طبيعي', 16, 4.8, 134, true),
('عسل الزعتر', 'عسل الزعتر البري الطبيعي من حقول الزعتر. يعالج التهابات الجهاز التنفسي والسعال.', 198, 'عسل طبيعي', 58, 4.8, 121, true),
('عسل البرية (Wildflower)', 'عسل الأزهار البرية الطبيعي المتعدد المصادر. غني بالإنزيمات والبوليفينول ومضادات الأكسدة.', 199, 'عسل طبيعي', 50, 4.7, 94, true);
