-- 1. حذف المنتجات القديمة
DELETE FROM public.products;

-- 2. إدراج المنتجات الحقيقية من المتجر

-- ── مكملات غذائية (Dietary Supplements) ───────────────────────

-- ── أعشاب طبية (Medicinal Herbs) ────────────────────────────────

-- ── زيوت طبية (Medicinal Oils) ──────────────────────────────────

-- ── عسل طبيعي (Natural Honey) ───────────────────────────────────

-- 3. تحقق من النتيجة
SELECT category, COUNT(*) as count, MIN(price) as min_price, MAX(price) as max_price 
FROM public.products 
GROUP BY category 
ORDER BY category;
